import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { productService } from '../../services/api'
import { showToast } from '../../utils/toast'
import PondChartCard from '../../components/charts/PondChartCard'
import '../../styles/product-management.css'

const emptyCategoryForm = {
  categoryName: '',
  note: '',
}

const emptyProductForm = {
  categoryId: '',
  categoryName: '',
  productName: '',
  unit: '',
  supplier: '',
  unitPrice: '',
  note: '',
}

const emptyOverview = {
  totalCategories: 0,
  totalProducts: 0,
  totalSuppliers: 0,
  topCategory: null,
  categoryStats: [],
  supplierStats: [],
  topProducts: [],
}

const PAGE_SIZE = 8

const formatDateTime = (value) => {
  if (!value) return '-'
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return value

  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'Asia/Ho_Chi_Minh',
  }).format(date)
}

const formatCurrency = (value) => {
  const amount = Number(value || 0)
  return `${amount.toLocaleString('vi-VN')} đ`
}

const normalizeText = (value) => String(value || '').trim().toLowerCase()

const createPalette = (baseColors) => (index) =>
  baseColors[index % baseColors.length]

const pickCategoryColor = createPalette([
  '#3b82f6',
  '#10b981',
  '#f59e0b',
  '#8b5cf6',
  '#06b6d4',
  '#ef4444',
])

const pickSupplierColor = createPalette([
  '#0ea5e9',
  '#22c55e',
  '#f97316',
  '#a855f7',
  '#f43f5e',
  '#64748b',
])

const pickProductColor = createPalette([
  '#0284c7',
  '#0f766e',
  '#f59e0b',
  '#7c3aed',
  '#16a34a',
  '#ef4444',
])

const ProductManagementPage = ({ roleLabel = 'Owner' }) => {
  const [overview, setOverview] = useState(emptyOverview)
  const [categories, setCategories] = useState([])
  const [products, setProducts] = useState([])
  const [loading, setLoading] = useState(true)

  const [activeTab, setActiveTab] = useState('products')

  const [categorySearch, setCategorySearch] = useState('')
  const [categoryFilter, setCategoryFilter] = useState('ALL')

  const [productSearch, setProductSearch] = useState('')
  const [supplierSearch, setSupplierSearch] = useState('')
  const [productCategoryFilter, setProductCategoryFilter] =
    useState('ALL')

  const [categoryPage, setCategoryPage] = useState(1)
  const [productPage, setProductPage] = useState(1)

  const fetchData = useCallback(async () => {
    try {
      setLoading(true)

      const [overviewRes, categoriesRes, productsRes] =
        await Promise.all([
          productService.getProductOverview(),
          productService.getProductCategories(),
          productService.getProducts(),
        ])

      setOverview(overviewRes?.data?.data || emptyOverview)
      setCategories(categoriesRes?.data?.data || [])
      setProducts(productsRes?.data?.data || [])
    } catch (err) {
      showToast({
        title:
          err?.response?.data?.message ||
          'Không tải được dữ liệu sản phẩm',
        type: 'error',
      })
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    fetchData()
  }, [fetchData])

  const totalSuppliers = useMemo(() => {
    const suppliers = new Set(
      products
        .map((item) => String(item.supplier || '').trim())
        .filter(Boolean)
    )

    return suppliers.size
  }, [products])

  const filteredCategories = useMemo(() => {
    return categories.filter((item) => {
      const matchesSearch =
        !categorySearch ||
        normalizeText(item.category_name).includes(
          normalizeText(categorySearch)
        )

      const count = Number(item.product_count || 0)

      const matchesFilter =
        categoryFilter === 'ALL'
          ? true
          : categoryFilter === 'HAS_PRODUCTS'
          ? count > 0
          : count === 0

      return matchesSearch && matchesFilter
    })
  }, [categories, categorySearch, categoryFilter])

  const filteredProducts = useMemo(() => {
    return products.filter((item) => {
      const matchesProduct =
        !productSearch ||
        normalizeText(item.product_name).includes(
          normalizeText(productSearch)
        )

      const matchesSupplier =
        !supplierSearch ||
        normalizeText(item.supplier).includes(
          normalizeText(supplierSearch)
        )

      const matchesCategory =
        productCategoryFilter === 'ALL' ||
        String(item.category_id) ===
          String(productCategoryFilter)

      return (
        matchesProduct &&
        matchesSupplier &&
        matchesCategory
      )
    })
  }, [
    products,
    productSearch,
    supplierSearch,
    productCategoryFilter,
  ])

  const categoryTotalPages = Math.max(
    1,
    Math.ceil(filteredCategories.length / PAGE_SIZE)
  )

  const productTotalPages = Math.max(
    1,
    Math.ceil(filteredProducts.length / PAGE_SIZE)
  )

  const categoryPageSafe = Math.min(
    categoryPage,
    categoryTotalPages
  )

  const productPageSafe = Math.min(
    productPage,
    productTotalPages
  )

  const paginatedCategories = filteredCategories.slice(
    (categoryPageSafe - 1) * PAGE_SIZE,
    categoryPageSafe * PAGE_SIZE
  )

  const paginatedProducts = filteredProducts.slice(
    (productPageSafe - 1) * PAGE_SIZE,
    productPageSafe * PAGE_SIZE
  )

  const categoryChartData = useMemo(() => {
    return (overview.categoryStats || []).map(
      (item, index) => ({
        label: item.label,
        value: Number(item.value || 0),
        color: pickCategoryColor(index),
      })
    )
  }, [overview.categoryStats])

  const supplierChartData = useMemo(() => {
    return (overview.supplierStats || []).map(
      (item, index) => ({
        label: item.label,
        value: Number(item.value || 0),
        color: pickSupplierColor(index),
      })
    )
  }, [overview.supplierStats])

  const productChartData = useMemo(() => {
    return (overview.topProducts || []).map(
      (item, index) => ({
        label: item.label,
        value: Number(item.value || 0),
        color: pickProductColor(index),
      })
    )
  }, [overview.topProducts])

  if (loading) {
    return (
      <div className="dashboard product-management_page">
        <div className="table-loading-container flex-center">
          <div className="spinner"></div>
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard product-management_page">
      <div className="product-management_header">
        <div>
          <h1>Quản lý sản phẩm</h1>
          <p>
            Quản lý danh mục và sản phẩm sử dụng
            trong trại nuôi
          </p>
        </div>

        <div className="product-management_header-actions">
          <button className="btn btn-primary">
            + Thêm sản phẩm
          </button>

          <button className="btn btn-secondary">
            + Thêm danh mục
          </button>
        </div>
      </div>

      <div className="stats-grid">
        <div className="stats-card stats-card--primary stats-card-row">
          <div className="stats-card-icon">📂</div>

          <div className="stats-card-content">
            <span className="stats-card-label">
              Tổng danh mục
            </span>

            <strong className="stats-card-value">
              {overview.totalCategories}
            </strong>

            <span className="stats-card-subtitle">
              Dữ liệu theo trại {roleLabel}
            </span>
          </div>
        </div>

        <div className="stats-card stats-card--success stats-card-row">
          <div className="stats-card-icon">🧪</div>

          <div className="stats-card-content">
            <span className="stats-card-label">
              Tổng sản phẩm
            </span>

            <strong className="stats-card-value">
              {overview.totalProducts}
            </strong>

            <span className="stats-card-subtitle">
              Dùng cho toàn bộ nghiệp vụ
            </span>
          </div>
        </div>

        <div className="stats-card stats-card--warning stats-card-row">
          <div className="stats-card-icon">🏷️</div>

          <div className="stats-card-content">
            <span className="stats-card-label">
              Nhà cung cấp
            </span>

            <strong className="stats-card-value">
              {totalSuppliers}
            </strong>

            <span className="stats-card-subtitle">
              Từ dữ liệu hiện có
            </span>
          </div>
        </div>

        <div className="stats-card stats-card--info stats-card-row">
          <div className="stats-card-icon">⭐</div>

          <div className="stats-card-content">
            <span className="stats-card-label">
              Danh mục nổi bật
            </span>

            <strong className="stats-card-value">
              {overview.topCategory?.label || '-'}
            </strong>

            <span className="stats-card-subtitle">
              {overview.topCategory
                ? `${overview.topCategory.value} sản phẩm`
                : 'Chưa có dữ liệu'}
            </span>
          </div>
        </div>
      </div>

      <div className="product-management_chart-grid">
        <PondChartCard
          prefix="product-management"
          title="Số lượng sản phẩm theo danh mục"
          type="doughnut"
          data={categoryChartData}
          total={overview.totalProducts}
        />

        <PondChartCard
          prefix="product-management"
          title="Phân bố theo nhà cung cấp"
          type="bar"
          data={supplierChartData}
        />

        <PondChartCard
          prefix="product-management"
          title="Sản phẩm sử dụng nhiều"
          type="bar"
          data={productChartData}
        />
      </div>

      <div className="product-management_tabs">
        <button
          className={`product-management_tab ${
            activeTab === 'products'
              ? 'product-management_tab--active'
              : ''
          }`}
          onClick={() => setActiveTab('products')}
        >
          Sản phẩm
        </button>

        <button
          className={`product-management_tab ${
            activeTab === 'categories'
              ? 'product-management_tab--active'
              : ''
          }`}
          onClick={() => setActiveTab('categories')}
        >
          Danh mục
        </button>
      </div>

      {activeTab === 'products' ? (
        <div className="table-panel">
          <div className="table-header">
            <div>
              <h2>
                Danh sách sản phẩm (
                {filteredProducts.length})
              </h2>

              <p className="table-subtitle">
                Dữ liệu dùng chung trong toàn trại
              </p>
            </div>
          </div>

          <div className="table-toolbar">
            <div className="table-search">
              <span className="table-search-icon">
                ⌕
              </span>

              <input
                type="search"
                placeholder="Tìm tên sản phẩm"
                value={productSearch}
                onChange={(e) => {
                  setProductSearch(e.target.value)
                  setProductPage(1)
                }}
              />
            </div>

            <div className="table-search">
              <span className="table-search-icon">
                ⌕
              </span>

              <input
                type="search"
                placeholder="Tìm nhà cung cấp"
                value={supplierSearch}
                onChange={(e) => {
                  setSupplierSearch(e.target.value)
                  setProductPage(1)
                }}
              />
            </div>

            <select
              className="table-filter"
              value={productCategoryFilter}
              onChange={(e) => {
                setProductCategoryFilter(e.target.value)
                setProductPage(1)
              }}
            >
              <option value="ALL">
                Tất cả danh mục
              </option>

              {categories.map((category) => (
                <option
                  key={category.category_id}
                  value={category.category_id}
                >
                  {category.category_name}
                </option>
              ))}
            </select>
          </div>

          <div className="table-wrapper">
            <table className="table-base">
              <thead>
                <tr>
                  <th>Tên sản phẩm</th>
                  <th>Nhà cung cấp</th>
                  <th>Đơn vị</th>
                  <th>Giá</th>
                  <th>Danh mục</th>
                  <th>Cập nhật</th>
                  <th>Hành động</th>
                </tr>
              </thead>

              <tbody>
                {paginatedProducts.length > 0 ? (
                  paginatedProducts.map((product) => (
                    <tr key={product.product_id}>
                      <td>
                        <strong>
                          {product.product_name}
                        </strong>

                        <div className="product-management_row-subtext">
                          {product.product_code}
                        </div>
                      </td>

                      <td>
                        {product.supplier || '-'}
                      </td>

                      <td>{product.unit || '-'}</td>

                      <td>
                        {formatCurrency(
                          product.unit_price
                        )}
                      </td>

                      <td>
                        {product.category_name || '-'}
                      </td>

                      <td>
                        {formatDateTime(
                          product.updated_at
                        )}
                      </td>

                      <td>
                        <div className="table-actions">
                          <button className="table-action-btn table-action-btn--view">
                            👁
                          </button>

                          <button className="table-action-btn table-action-btn--edit">
                            ✎
                          </button>

                          <button className="table-action-btn table-action-btn--delete">
                            🗑
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td
                      colSpan="7"
                      className="table-empty-row"
                    >
                      Không có sản phẩm phù hợp
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

          <div className="table-pagination">
            <div className="table-pagination-left">
              <span>
                Trang {productPageSafe}/
                {productTotalPages}
              </span>
            </div>

            <div className="table-pagination-right">
              <button
                className="btn btn-sm btn-secondary"
                disabled={productPageSafe <= 1}
                onClick={() =>
                  setProductPage((prev) =>
                    Math.max(1, prev - 1)
                  )
                }
              >
                ‹
              </button>

              <div className="table-page-pill">
                {productPageSafe}
              </div>

              <button
                className="btn btn-sm btn-secondary"
                disabled={
                  productPageSafe >= productTotalPages
                }
                onClick={() =>
                  setProductPage((prev) =>
                    Math.min(
                      productTotalPages,
                      prev + 1
                    )
                  )
                }
              >
                ›
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </div>
  )
}

export default ProductManagementPage
